settings.custom_liquid:
{% assign ns = 'custom' %}

{%- if product.metafields[ns].notes_tete.value != blank 
   or product.metafields[ns].notes_coeur.value != blank 
   or product.metafields[ns].notes_fond.value != blank -%}

<div style="margin: 3rem 0; padding: 2.2rem; max-width: 920px; margin-left: auto; margin-right: auto;
            background: linear-gradient(180deg, #fdfcfb 0%, #f8f7f5 100%);  /* Fond subtil blanc cassé → gris très clair (monochrome luxe) */
            border: 1px solid #e8e6e2; border-radius: 10px; 
            box-shadow: 0 6px 24px rgba(0,0,0,0.04); /* Ombre discrète pour profondeur */
            ">

  <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 2.5rem; text-align: center;">

    <!-- TÊTE -->
    {%- if product.metafields[ns].notes_tete.value != blank -%}
    <div>
      <strong style="display: block; font-size: 1.18rem; font-weight: 600; color: #2a2a2a; margin-bottom: 0.9rem; text-transform: uppercase; letter-spacing: 0.8px;">
        Tête
      </strong>
      <p style="margin: 0; font-size: 1.02rem; line-height: 1.6; color: #444444;">
        {{ product.metafields[ns].notes_tete.value }}
      </p>
    </div>
    {%- endif -%}

    <!-- CŒUR -->
    {%- if product.metafields[ns].notes_coeur.value != blank -%}
    <div>
      <strong style="display: block; font-size: 1.18rem; font-weight: 600; color: #2a2a2a; margin-bottom: 0.9rem; text-transform: uppercase; letter-spacing: 0.8px;">
        Cœur
      </strong>
      <p style="margin: 0; font-size: 1.02rem; line-height: 1.6; color: #444444;">
        {{ product.metafields[ns].notes_coeur.value }}
      </p>
    </div>
    {%- endif -%}

    <!-- FOND -->
    {%- if product.metafields[ns].notes_fond.value != blank -%}
    <div>
      <strong style="display: block; font-size: 1.18rem; font-weight: 600; color: #2a2a2a; margin-bottom: 0.9rem; text-transform: uppercase; letter-spacing: 0.8px;">
        Fond
      </strong>
      <p style="margin: 0; font-size: 1.02rem; line-height: 1.6; color: #444444;">
        {{ product.metafields[ns].notes_fond.value }}
      </p>
    </div>
    {%- endif -%}

  </div>
</div>

<style>
  @media (max-width: 768px) {
    div[style*="grid-template-columns"] { grid-template-columns: 1fr !important; gap: 2rem !important; }
  }
</style>

{%- endif -%}
